// ═══════════════════════════════════════════════════════════════════════════════
// GLOSSARY DATA
// term, abbr (optional), category, definition, doc (optional)
// categories: core, ocp, operators, networking, storage, security, monitoring, builds, advanced, odf, backup, virt, multicluster, acronym
// ═══════════════════════════════════════════════════════════════════════════════
export const glossaryTerms = [
// ── Kubernetes Core ───────────────────────────────────────────────────────────
{term:"Pod",cat:"core",def:"The smallest deployable unit in Kubernetes. One or more containers that share a network namespace (same IP), storage volumes, and lifecycle. Containers inside a pod communicate over localhost. Pods are ephemeral — they are replaced, not updated in place.",doc:"https://kubernetes.io/docs/concepts/workloads/pods/"},
{term:"Container",cat:"core",def:"A lightweight, standalone executable package that includes code, runtime, system tools, libraries, and settings. Containers share the host OS kernel but are isolated via Linux namespaces and cgroups. In Kubernetes, CRI-O or containerd manages container lifecycle on each node.",doc:"https://kubernetes.io/docs/concepts/containers/"},
{term:"Namespace",cat:"core",def:"A virtual cluster within Kubernetes that provides isolation for resources. Names must be unique within a namespace but not across namespaces. Cluster-scoped resources (Nodes, PersistentVolumes, ClusterRoles) are not namespaced. In OpenShift, Projects wrap Namespaces.",doc:"https://kubernetes.io/docs/concepts/overview/working-with-objects/namespaces/"},
{term:"Deployment",cat:"core",def:"A declarative way to manage stateless applications. Describes desired state (image, replicas, update strategy). Manages ReplicaSets to provide rolling updates, rollback history, and self-healing. The primary workload resource for stateless apps.",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/"},
{term:"ReplicaSet",cat:"core",def:"Ensures a specified number of pod replicas run at all times. Owned by a Deployment. Rarely created directly — use Deployments. Uses label selectors to identify its pods. Creates new pods when existing ones are deleted.",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/replicaset/"},
{term:"StatefulSet",cat:"core",def:"Manages stateful applications. Provides stable network identities (pod-0, pod-1), stable persistent storage via volumeClaimTemplates, and ordered pod deployment/termination. Required for databases and distributed systems that need stable identities.",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/statefulset/"},
{term:"DaemonSet",cat:"core",def:"Ensures exactly one Pod runs on every (or selected) node. As nodes join the cluster, pods are automatically added. Used for node-level agents: log collectors, monitoring exporters, network plugins, and storage daemons.",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/"},
{term:"Job",cat:"core",def:"Creates one or more pods and ensures a specified number complete successfully. Retries failed pods up to backoffLimit. Used for batch processing, database migrations, report generation. The pod restartPolicy must be OnFailure or Never (not Always).",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/job/"},
{term:"CronJob",cat:"core",def:"Creates Jobs on a recurring schedule using standard cron syntax. Manages job history via successfulJobsHistoryLimit and failedJobsHistoryLimit. The concurrencyPolicy controls behavior when a job is still running when the next schedule fires: Allow, Forbid, or Replace.",doc:"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/"},
{term:"Service",cat:"core",def:"Provides a stable network endpoint (DNS name + virtual IP) for a set of pods selected by labels. Types: ClusterIP (internal), NodePort (node-level external), LoadBalancer (cloud LB), ExternalName (DNS alias). Services are load balanced across all healthy pods in the selector.",doc:"https://kubernetes.io/docs/concepts/services-networking/service/"},
{term:"ConfigMap",cat:"core",def:"Stores non-sensitive configuration as key-value pairs or file content. Consumed by pods as environment variables (envFrom, valueFrom) or mounted as files (volume). Values are stored in plain text — never use for secrets. Updating a mounted ConfigMap takes ~1-2 minutes to reflect in pods.",doc:"https://kubernetes.io/docs/concepts/configuration/configmap/"},
{term:"Secret",cat:"core",def:"Stores sensitive data (passwords, tokens, TLS certificates). Values are base64-encoded by default — not encrypted. Types: Opaque (generic), kubernetes.io/tls, kubernetes.io/dockerconfigjson, kubernetes.io/service-account-token. Enable etcd encryption at rest for true security.",doc:"https://kubernetes.io/docs/concepts/configuration/secret/"},
{term:"ServiceAccount",cat:"core",def:"A non-human identity for processes running in pods. Every pod runs as a service account (default: 'default'). The API server automatically mounts a token for the SA into the pod. Grant RBAC roles to SAs when pods need to call the Kubernetes API.",doc:"https://kubernetes.io/docs/concepts/security/service-accounts/"},
{term:"PersistentVolume",abbr:"PV",cat:"core",def:"A cluster-level storage resource provisioned by an admin or dynamically by a StorageClass. Has capacity, access modes (RWO/ROX/RWX/RWOP), and a reclaim policy (Retain/Delete). Lifecycle is independent of any pod — data persists when pods are deleted.",doc:"https://kubernetes.io/docs/concepts/storage/persistent-volumes/"},
{term:"PersistentVolumeClaim",abbr:"PVC",cat:"core",def:"A namespace-scoped request for storage. Specifies size and access mode. The control plane binds it to a matching PV. Pods mount PVCs as volumes. If no PV matches and a default StorageClass exists, dynamic provisioning creates a PV automatically.",doc:"https://kubernetes.io/docs/concepts/storage/persistent-volumes/#persistentvolumeclaims"},
{term:"StorageClass",abbr:"SC",cat:"core",def:"Defines a 'class' of storage (SSD, NFS, Ceph RBD) with a provisioner plugin. When a PVC references a StorageClass, a PV is dynamically provisioned. The 'default' StorageClass is used when no class is specified. Admins set one StorageClass as the default per cluster.",doc:"https://kubernetes.io/docs/concepts/storage/storage-classes/"},
{term:"VolumeSnapshot",cat:"core",def:"A point-in-time snapshot of a PersistentVolumeClaim. Used for backup and restore workflows, or creating new PVCs pre-populated with data. Requires a CSI driver that supports snapshots. Analogous to taking a VM disk snapshot.",doc:"https://kubernetes.io/docs/concepts/storage/volume-snapshots/"},
{term:"VolumeSnapshotClass",cat:"core",def:"Defines the provisioner and parameters for VolumeSnapshots, similar to how StorageClasses define PV provisioners. Specifies deletion policy (Delete or Retain) for snapshots.",doc:"https://kubernetes.io/docs/concepts/storage/volume-snapshot-classes/"},
{term:"HorizontalPodAutoscaler",abbr:"HPA",cat:"core",def:"Automatically scales Deployment/StatefulSet replicas based on observed CPU/memory or custom metrics. Requires resource requests to be set and the Metrics Server (or Prometheus Adapter) to be installed. Scale-up is fast; scale-down has a stabilization window (default 5 min) to prevent flapping.",doc:"https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale/"},
{term:"VerticalPodAutoscaler",abbr:"VPA",cat:"core",def:"Automatically adjusts CPU and memory requests/limits for containers based on historical usage. Can operate in Off (recommendations only), Initial (set at pod creation), or Auto (restart pods to apply) mode. Conflicts with HPA on CPU/memory — use HPA for replicas, VPA for right-sizing.",doc:"https://github.com/kubernetes/autoscaler/tree/master/vertical-pod-autoscaler"},
{term:"PodDisruptionBudget",abbr:"PDB",cat:"core",def:"Specifies the minimum number of pods (minAvailable) or maximum disrupted pods (maxUnavailable) during voluntary disruptions (node drain, rolling update, cluster upgrade). Prevents the cluster from taking down too many replicas at once.",doc:"https://kubernetes.io/docs/tasks/run-application/configure-pdb/"},
{term:"ResourceQuota",cat:"core",def:"Sets an upper bound on total resource consumption in a namespace: compute (CPU, memory), object counts (pods, services, PVCs), and storage. When a quota is exceeded, creation is rejected with 403 Forbidden. Must be combined with LimitRange to set defaults.",doc:"https://kubernetes.io/docs/concepts/policy/resource-quotas/"},
{term:"LimitRange",cat:"core",def:"Sets default resource requests/limits (applied when a container omits them) and enforces min/max bounds per container or pod within a namespace. Required when a ResourceQuota is active — otherwise pods without requests/limits are rejected.",doc:"https://kubernetes.io/docs/concepts/policy/limit-range/"},
{term:"NetworkPolicy",cat:"core",def:"A namespace-scoped firewall rule for pods. Selects pods with labels and defines ingress/egress traffic rules. With no NetworkPolicy selecting a pod, all traffic is allowed. Once a NetworkPolicy selects a pod, only explicitly allowed traffic passes.",doc:"https://kubernetes.io/docs/concepts/services-networking/network-policies/"},
{term:"Ingress",cat:"core",def:"A Kubernetes API resource that manages external access to Services, typically HTTP/HTTPS. Defines rules (hostname, path) to route to backend Services. Requires an Ingress Controller (e.g., nginx-ingress, HAProxy). In OpenShift, Routes are the native equivalent with more features.",doc:"https://kubernetes.io/docs/concepts/services-networking/ingress/"},
{term:"EndpointSlice",cat:"core",def:"Tracks the network endpoints (IP:port pairs) for a Service. Replaced the older Endpoints resource for scalability — each EndpointSlice holds up to 100 endpoints. kube-proxy watches EndpointSlices to program routing rules.",doc:"https://kubernetes.io/docs/concepts/services-networking/endpoint-slices/"},
{term:"CustomResourceDefinition",abbr:"CRD",cat:"core",def:"Extends the Kubernetes API with new resource types. Once a CRD is created, you can create Custom Resources (CRs) of that type via the API. Operators define and use CRDs to manage complex applications. View all CRDs with: oc get crd",doc:"https://kubernetes.io/docs/concepts/extend-kubernetes/api-extension/custom-resources/"},
{term:"Role",cat:"core",def:"Defines a set of permissions (verbs on API resources) scoped to a single namespace. Example: allow get, list, watch on pods. Applied to subjects via RoleBinding. For cluster-wide permissions, use ClusterRole.",doc:"https://kubernetes.io/docs/reference/access-authn-authz/rbac/#role-and-clusterrole"},
{term:"ClusterRole",cat:"core",def:"Like Role but cluster-scoped. Can grant access to non-namespaced resources (Nodes, PVs) or be applied across all namespaces via ClusterRoleBinding. Can also be used namespace-scoped via RoleBinding (useful for reusable role definitions).",doc:"https://kubernetes.io/docs/reference/access-authn-authz/rbac/#role-and-clusterrole"},
{term:"RoleBinding",cat:"core",def:"Grants a Role (or ClusterRole) to subjects (Users, Groups, ServiceAccounts) within a specific namespace. References exactly one Role or ClusterRole. Created automatically by: oc adm policy add-role-to-user.",doc:"https://kubernetes.io/docs/reference/access-authn-authz/rbac/#rolebinding-and-clusterrolebinding"},
{term:"ClusterRoleBinding",cat:"core",def:"Grants a ClusterRole to subjects across the entire cluster (all namespaces). Use for cluster-admin and other cluster-wide roles. More powerful than RoleBinding — use sparingly and prefer namespace-scoped RoleBindings when possible.",doc:"https://kubernetes.io/docs/reference/access-authn-authz/rbac/#rolebinding-and-clusterrolebinding"},
{term:"Node",cat:"core",def:"A worker machine in Kubernetes — physical or virtual. Runs the kubelet (pod management), kube-proxy (networking), and a container runtime (CRI-O). Nodes have labels (zone, instance type) used by the scheduler. Cordoned nodes don't accept new pods; drained nodes evict existing pods.",doc:"https://kubernetes.io/docs/concepts/architecture/nodes/"},
{term:"Taint",cat:"core",def:"Applied to nodes to repel pods that don't explicitly tolerate them. Effects: NoSchedule (new pods rejected), PreferNoSchedule (soft rejection), NoExecute (existing pods evicted). Added with: oc adm taint nodes <name> key=value:Effect",doc:"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/"},
{term:"Toleration",cat:"core",def:"Placed on pods to allow (not require) scheduling onto tainted nodes. Must match a taint's key, value, and effect. A pod tolerating a taint can still run on non-tainted nodes. Combine with nodeAffinity to both permit AND attract to tainted nodes.",doc:"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/"},
{term:"PriorityClass",cat:"core",def:"Defines the scheduling priority of a pod relative to other pods. Higher priority pods preempt lower priority pods when resources are scarce. System-critical: system-cluster-critical, system-node-critical. Define application tiers (high/medium/low) to control eviction order.",doc:"https://kubernetes.io/docs/concepts/scheduling-eviction/pod-priority-preemption/"},
{term:"RuntimeClass",cat:"core",def:"Selects the container runtime configuration for a pod. Allows different pods to use different runtimes (e.g., gVisor for untrusted workloads, kata-containers for VM-level isolation, standard runc for normal workloads). Set via pod.spec.runtimeClassName.",doc:"https://kubernetes.io/docs/concepts/containers/runtime-class/"},
{term:"CertificateSigningRequest",abbr:"CSR",cat:"core",def:"A Kubernetes API object for requesting TLS certificate signing from the cluster's CA. Admins or automated controllers approve or deny CSRs. Used by kubelets to get node certificates. View pending CSRs: oc get csr",doc:"https://kubernetes.io/docs/reference/access-authn-authz/certificate-signing-requests/"},
{term:"Lease",cat:"core",def:"A lightweight Kubernetes object used for leader election among controller replicas and kubelet node heartbeats. Each node has a Lease in the kube-node-lease namespace updated every 10 seconds. If a Lease expires, the node is considered unavailable.",doc:"https://kubernetes.io/docs/concepts/architecture/leases/"},
// ── OpenShift Specific ────────────────────────────────────────────────────────
{term:"Project",cat:"ocp",def:"An OpenShift wrapper around a Kubernetes Namespace with additional metadata: requester, displayName, description. Creating a Project with 'oc new-project' also applies default LimitRanges, NetworkPolicies, and RBAC. All OpenShift projects are namespaces, but not all namespaces are projects.",doc:"https://docs.openshift.com/container-platform/4.18/applications/projects/working-with-projects.html"},
{term:"Route",cat:"ocp",def:"An OpenShift-specific resource that exposes a Service externally via the HAProxy Ingress Router. Supports edge, passthrough, and reencrypt TLS termination. Automatically gets a hostname under the cluster's wildcard domain. Created with: oc expose svc/<name>",doc:"https://docs.openshift.com/container-platform/4.18/networking/routes/route-configuration.html"},
{term:"DeploymentConfig",abbr:"DC",cat:"ocp",def:"An OpenShift-specific predecessor to Kubernetes Deployments. Adds image change triggers, config change triggers, and lifecycle hooks (pre/mid/post). In OCP 4.14+, standard Deployments are preferred. Existing DCs still work but migration is recommended.",doc:"https://docs.openshift.com/container-platform/4.18/applications/deployments/what-deployments-are.html"},
{term:"ImageStream",abbr:"IS",cat:"ocp",def:"An OpenShift abstraction that tracks a series of container images (by tag and SHA digest) without storing image layers. Deployments reference ImageStream tags; when a new image is pushed, image change triggers can automatically redeploy. View: oc get imagestreams",doc:"https://docs.openshift.com/container-platform/4.18/openshift_images/image-streams-manage.html"},
{term:"ImageStreamTag",abbr:"IST",cat:"ocp",def:"A named pointer within an ImageStream to a specific image version (identified by SHA digest). Example: nodejs:18 is the '18' tag on the 'nodejs' ImageStream. Tags can be updated to point to new images, triggering downstream deployments.",doc:"https://docs.openshift.com/container-platform/4.18/openshift_images/image-streams-manage.html"},
{term:"BuildConfig",abbr:"BC",cat:"ocp",def:"An OpenShift resource defining HOW to build a container image: source (Git, Binary, Dockerfile), strategy (Source/S2I, Docker, Custom), output (ImageStream), and triggers (Git webhook, ImageChange, ConfigChange). Runs builds in pods using Buildah.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/builds/understanding-buildconfigs.html"},
{term:"Build",cat:"ocp",def:"A single execution of a BuildConfig. Each build creates a pod that performs the build process and pushes the resulting image. View build logs with: oc logs -f bc/<name> or oc logs build/<name>. Build phases: New, Pending, Running, Complete, Failed, Error, Cancelled.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/builds/understanding-buildconfigs.html"},
{term:"Source-to-Image",abbr:"S2I",cat:"ocp",def:"An OpenShift build strategy that combines application source code with a builder image to produce a runnable container — no Dockerfile required. The builder image defines assemble (build) and run scripts. Supported runtimes: Node.js, Python, Ruby, PHP, Java, .NET, Go, Perl.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/builds/build-strategies.html"},
{term:"Template",cat:"ocp",def:"An OpenShift resource that defines a set of objects (Deployments, Services, Routes, etc.) with parameterized values. Used to create consistent application stacks. Process with: oc process -f template.yaml -p PARAM=value | oc apply -f -. Being superseded by Helm charts.",doc:"https://docs.openshift.com/container-platform/4.18/openshift_images/using-templates.html"},
{term:"EgressNetworkPolicy",cat:"ocp",def:"An OpenShift-specific NetworkPolicy that controls pod egress traffic to external IP ranges. Defines allow/deny rules based on destination CIDRs. Different from Kubernetes NetworkPolicy — applies to external (non-cluster) traffic from a namespace.",doc:"https://docs.openshift.com/container-platform/4.18/networking/openshift-sdn/egressnetworkpolicy.html"},
{term:"EgressIP",cat:"ocp",def:"Assigns a stable egress IP to a namespace so all outgoing traffic appears to come from a single known IP. Essential for firewall allowlisting — external systems can whitelist the EgressIP rather than individual pod IPs. Configured via EgressIP object.",doc:"https://docs.openshift.com/container-platform/4.18/networking/ovn_kubernetes_network_provider/assigning-egress-ips-ovn.html"},
{term:"OAuthClient",cat:"ocp",def:"Represents an application that can authenticate users through OpenShift's OAuth server. Stores client ID, client secret, and redirect URIs. The OpenShift web console itself is an OAuthClient. Used to integrate external tools (Jenkins, GitLab, Grafana) with cluster authentication.",doc:"https://docs.openshift.com/container-platform/4.18/authentication/configuring-oauth-clients.html"},
{term:"Identity",cat:"ocp",def:"Represents a user identity from an external identity provider (LDAP, GitHub, Google, OIDC). When a user logs in, OpenShift creates both a User object and an Identity object linking to the provider. View with: oc get identity",doc:"https://docs.openshift.com/container-platform/4.18/authentication/understanding-identity-provider.html"},
{term:"AppliedClusterResourceQuota",cat:"ocp",def:"A read-only view showing the effective ResourceQuota applied to a namespace from a ClusterResourceQuota (which targets multiple namespaces by selector). View which quotas apply to your project: oc get appliedclusterresourcequota",doc:"https://docs.openshift.com/container-platform/4.18/applications/quotas/quotas-setting-across-multiple-projects.html"},
// ── Operators & OLM ──────────────────────────────────────────────────────────
{term:"Operator Lifecycle Manager",abbr:"OLM",cat:"operators",def:"The OpenShift system that manages the full lifecycle of Operators: discovery (OperatorHub), installation (InstallPlan), updates (Subscription channels), and removal. Runs in the openshift-operator-lifecycle-manager namespace. Ensures operators don't conflict and stay on approved versions.",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-olm.html"},
{term:"ClusterServiceVersion",abbr:"CSV",cat:"operators",def:"The primary descriptor for an installed Operator. Contains: what CRDs it owns, what RBAC it requires, the operator Deployment spec, installation modes, icon, description, and version. The CSV is created by OLM after an InstallPlan is approved. A Succeeded CSV means the operator is running.",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-olm.html#olm-csv_olm-understanding-olm"},
{term:"Subscription",cat:"operators",def:"Tells OLM which operator you want installed, from which CatalogSource, on which update channel (stable, alpha, fast), and how upgrades are approved (Automatic or Manual). A Subscription is the ongoing 'wish' — OLM creates InstallPlans to fulfill it.",doc:"https://docs.openshift.com/container-platform/4.18/operators/admin/olm-adding-operators-to-cluster.html"},
{term:"InstallPlan",cat:"operators",def:"Created by OLM in response to a Subscription. Lists all Kubernetes resources that need to be created to install or upgrade an operator (CSVs, CRDs, RoleBindings). With Manual approval, an admin must patch it to approved:true before OLM proceeds.",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-olm.html#olm-installplan_olm-understanding-olm"},
{term:"CatalogSource",cat:"operators",def:"A registry of operator packages available for installation. OpenShift ships four default CatalogSources: redhat-operators, certified-operators, community-operators, redhat-marketplace. Each CatalogSource runs a pod (the catalog) that OLM queries for available packages.",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-olm.html#olm-catalogsource_olm-understanding-olm"},
{term:"OperatorGroup",cat:"operators",def:"Defines which namespaces an operator watches. Modes: AllNamespaces (watches cluster-wide), SingleNamespace (watches one namespace), MultiNamespace (watches a list of namespaces), OwnNamespace (watches only its install namespace). The OperatorGroup must be in the same namespace as the Subscription.",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-operatorgroups.html"},
{term:"PackageManifest",cat:"operators",def:"A read-only object in the openshift-marketplace namespace representing an operator available in a CatalogSource. Contains version info, channels, install modes, and CRD descriptions. Browse with: oc get packagemanifest -n openshift-marketplace",doc:"https://docs.openshift.com/container-platform/4.18/operators/understanding/olm/olm-understanding-olm.html"},
{term:"Custom Resource",abbr:"CR",cat:"operators",def:"An instance of a CustomResourceDefinition (CRD). The API for using an Operator — you create a CR describing WHAT you want (e.g., a 3-node Elasticsearch cluster), and the Operator controller reconciles it into real Kubernetes resources. The CR is your interface to the operator.",doc:"https://kubernetes.io/docs/concepts/extend-kubernetes/api-extension/custom-resources/"},
// ── Networking ────────────────────────────────────────────────────────────────
{term:"OVN-Kubernetes",cat:"networking",def:"The default CNI (Container Network Interface) plugin in OpenShift 4.x. Based on Open Virtual Network, it implements pod networking, Services, NetworkPolicies, and EgressIPs using OpenFlow rules on Open vSwitch. Replaced OpenShift SDN as the default in OCP 4.12.",doc:"https://docs.openshift.com/container-platform/4.18/networking/ovn_kubernetes_network_provider/about-ovn-kubernetes.html"},
{term:"IngressController",cat:"networking",def:"The OpenShift resource that manages the HAProxy router pods responsible for handling Route traffic. The default IngressController (in openshift-ingress namespace) handles all Routes. You can create additional IngressControllers for dedicated routers (e.g., internal vs external).",doc:"https://docs.openshift.com/container-platform/4.18/networking/ingress-operator.html"},
{term:"ClusterNetwork",cat:"networking",def:"An OpenShift CRD (from the network.operator.openshift.io group) that defines the cluster's network configuration: pod CIDR, service CIDR, and MTU. View with: oc get network.config.openshift.io/cluster -o yaml. Changing this after installation is complex and disruptive.",doc:"https://docs.openshift.com/container-platform/4.18/networking/cluster-network-operator.html"},
{term:"HostSubnet",cat:"networking",def:"An OpenShift SDN (legacy) object that maps a node to its allocated subnet for pod IPs. One HostSubnet per node. In OVN-Kubernetes clusters, this is replaced by OVN logical topology objects. Still visible in SDN-mode clusters.",doc:"https://docs.openshift.com/container-platform/4.18/networking/openshift-sdn/about-openshift-sdn.html"},
{term:"NetNamespace",cat:"networking",def:"An OpenShift SDN object representing a network namespace for a project. Contains the Virtual Network ID (VNID) used to isolate traffic between projects in multitenant SDN mode. Each project gets a unique VNID. Obsolete with OVN-Kubernetes.",doc:"https://docs.openshift.com/container-platform/4.18/networking/openshift-sdn/about-openshift-sdn.html"},
{term:"ServiceMesh",cat:"networking",def:"OpenShift Service Mesh (based on Istio) adds mTLS, traffic management, observability (Jaeger tracing, Kiali graph), and fine-grained access control between services — without changing application code. The Envoy sidecar proxy is injected into each pod automatically.",doc:"https://docs.openshift.com/container-platform/4.18/service_mesh/v2x/ossm-about.html"},
// ── Security ─────────────────────────────────────────────────────────────────
{term:"SecurityContextConstraints",abbr:"SCC",cat:"security",def:"OpenShift's admission plugin that controls what security privileges a pod can request. Each pod must satisfy at least one SCC available to its ServiceAccount. Built-in SCCs from most to least restrictive: restricted-v2, nonroot, anyuid, privileged. Required whenever a pod needs to run as a specific UID or access host resources.",doc:"https://docs.openshift.com/container-platform/4.18/authentication/managing-security-context-constraints.html"},
{term:"ValidatingWebhookConfiguration",cat:"security",def:"A cluster-scoped resource that registers a webhook called by the API server before persisting an object. The webhook can approve or reject the request. Used by OPA Gatekeeper, Kyverno, and OpenShift's own admission controllers for policy enforcement. View all: oc get validatingwebhookconfigurations",doc:"https://kubernetes.io/docs/reference/access-authn-authz/extensible-admission-controllers/"},
{term:"MutatingWebhookConfiguration",cat:"security",def:"Like ValidatingWebhookConfiguration but can modify the object before it's stored. Used for automatic sidecar injection (service mesh), adding default labels, injecting environment variables, and setting default resource limits. Mutations happen before validation.",doc:"https://kubernetes.io/docs/reference/access-authn-authz/extensible-admission-controllers/"},
{term:"Pod Security Admission",abbr:"PSA",cat:"security",def:"A Kubernetes built-in admission controller (1.25+) enforcing Pod Security Standards at the namespace level via labels. Three profiles: privileged (no restrictions), baseline (prevents known escalations), restricted (hardened). OpenShift 4.11+ enforces both PSA and SCC.",doc:"https://kubernetes.io/docs/concepts/security/pod-security-admission/"},
{term:"ServiceCA",cat:"security",def:"OpenShift's built-in Service Certificate Authority. Automatically provisions TLS certificates for Services annotated with service.beta.openshift.io/serving-cert-secret-name. The certificate is valid for the Service's DNS name and is rotated automatically. Enables easy in-cluster mTLS without cert-manager.",doc:"https://docs.openshift.com/container-platform/4.18/security/certificates/service-serving-certificate.html"},
{term:"TokenReview",cat:"security",def:"A Kubernetes API that validates a token — checks if it's valid and returns the associated user/groups. Used by services that receive bearer tokens and need to verify them against the Kubernetes API server without storing credentials themselves.",doc:"https://kubernetes.io/docs/reference/kubernetes-api/authentication-resources/token-review-v1/"},
{term:"SubjectAccessReview",cat:"security",def:"A Kubernetes API for checking whether a specific user or ServiceAccount can perform a given action. Equivalent to: oc auth can-i get pods --as=alice. Used by operators and webhooks to make authorization decisions programmatically.",doc:"https://kubernetes.io/docs/reference/kubernetes-api/authorization-resources/subject-access-review-v1/"},
// ── Monitoring ───────────────────────────────────────────────────────────────
{term:"ServiceMonitor",cat:"monitoring",def:"A Prometheus Operator CRD that defines how Prometheus should scrape a Service's metrics endpoint. Selects Services by label, specifies the port, path, scrape interval, and scheme. Requires user-workload-monitoring to be enabled for app namespaces.",doc:"https://docs.openshift.com/container-platform/4.18/monitoring/enabling-monitoring-for-user-defined-projects.html"},
{term:"PodMonitor",cat:"monitoring",def:"Like ServiceMonitor but scrapes pods directly without going through a Service. Useful for jobs, batch workloads, or pods that don't have a Service. Selects pods by label and scrapes their metrics endpoint.",doc:"https://docs.openshift.com/container-platform/4.18/monitoring/enabling-monitoring-for-user-defined-projects.html"},
{term:"PrometheusRule",cat:"monitoring",def:"A Prometheus Operator CRD defining alerting rules and recording rules in PromQL. Alerting rules fire alerts when an expression is true for a duration. Recording rules precompute expensive queries into new time series. In OCP, rules for user workloads need the leaf-prometheus scope label.",doc:"https://docs.openshift.com/container-platform/4.18/monitoring/managing-alerts.html"},
{term:"AlertmanagerConfig",cat:"monitoring",def:"Configures routing, grouping, and receivers for alerts in a specific namespace. Routes alerts to Slack, PagerDuty, email, or webhooks. Namespaced (unlike the global Alertmanager config). Requires user-workload-monitoring.",doc:"https://docs.openshift.com/container-platform/4.18/monitoring/managing-alerts.html"},
{term:"Thanos",cat:"monitoring",def:"A highly available, long-term storage extension for Prometheus. OpenShift uses Thanos components (Querier, Ruler, Store) internally for the monitoring stack. The Thanos Querier in openshift-monitoring aggregates metrics from both the platform and user-workload Prometheus instances.",doc:"https://thanos.io/"},
{term:"Cluster Monitoring Operator",abbr:"CMO",cat:"monitoring",def:"An OpenShift cluster operator (clusteroperator/monitoring) that manages the entire monitoring stack: Prometheus, Alertmanager, Thanos, kube-state-metrics, node-exporter, Prometheus Adapter. Configured via the cluster-monitoring-config ConfigMap in openshift-monitoring.",doc:"https://docs.openshift.com/container-platform/4.18/monitoring/monitoring-overview.html"},
// ── Builds & CI/CD ───────────────────────────────────────────────────────────
{term:"Pipeline",cat:"builds",def:"A Tekton Pipeline resource defining a sequence of Tasks to run a CI/CD workflow. Tasks run sequentially or in parallel. Pipelines are parameterized and reusable. OpenShift Pipelines (Tekton) is the recommended CI/CD system for OCP 4.x.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"PipelineRun",cat:"builds",def:"An execution instance of a Pipeline with specific parameters and workspace bindings. Creates TaskRun objects for each Task. View logs: tkn pipelinerun logs <name> -f. History is kept based on successfulRunsRetentionLimit and failedRunsRetentionLimit.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"Task",cat:"builds",def:"The basic building block of a Tekton Pipeline. A Task contains Steps (containers) that run sequentially. Tasks can be parameterized and can use Workspaces for shared storage. ClusterTasks are cluster-scoped (deprecated — use Tasks with remote resolution instead).",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"TaskRun",cat:"builds",def:"An execution instance of a Task with specific parameters. Created automatically by a PipelineRun, or manually to test a Task. Each Step in the Task runs as a separate container in the TaskRun pod.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"EventListener",cat:"builds",def:"A Tekton Triggers resource that listens for incoming webhook events (GitHub push, GitLab MR, Quay image push) and triggers PipelineRuns. Runs as a pod+service. Combined with TriggerTemplate and TriggerBinding for full GitOps automation.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"TriggerTemplate",cat:"builds",def:"Defines what Kubernetes resources to create (typically a PipelineRun) when an EventListener receives an event. References parameters extracted by a TriggerBinding (e.g., git commit SHA, repo URL).",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"TriggerBinding",cat:"builds",def:"Extracts parameters from an incoming webhook payload (JSON body, headers) for use in a TriggerTemplate. Example: extracting the git repository URL and branch name from a GitHub push event.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/pipelines/understanding-openshift-pipelines.html"},
{term:"GitOps",cat:"builds",def:"A deployment approach where the desired cluster state is stored in Git. A controller (ArgoCD / OpenShift GitOps) continuously syncs the cluster to match the Git repository. Changes go through Git (PRs, reviews) rather than direct kubectl/oc commands. Audit trail is the Git history.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/gitops/understanding-openshift-gitops.html"},
{term:"ArgoCD",cat:"builds",def:"The GitOps continuous delivery controller used by OpenShift GitOps (an operator). Watches Git repositories and syncs Kubernetes manifests to the cluster. Provides a web UI showing sync status, diff between desired and actual state, and rollback capability.",doc:"https://docs.openshift.com/container-platform/4.18/cicd/gitops/understanding-openshift-gitops.html"},
// ── Advanced / Platform Engineering ──────────────────────────────────────────
{term:"ClusterVersion",cat:"advanced",def:"A cluster-scoped singleton resource (cluster) that tracks the current OpenShift version, available updates, and update history. The ClusterVersionOperator (CVO) reads this object and drives cluster upgrades. View: oc get clusterversion",doc:"https://docs.openshift.com/container-platform/4.18/updating/understanding_updates/how-updates-work.html"},
{term:"ClusterVersionOperator",abbr:"CVO",cat:"advanced",def:"The operator responsible for managing OpenShift cluster upgrades. Reads the ClusterVersion object, downloads the release payload, and applies manifests for all cluster operators in dependency order. Drives the entire 'oc adm upgrade' process.",doc:"https://docs.openshift.com/container-platform/4.18/updating/understanding_updates/how-updates-work.html"},
{term:"ClusterOperator",cat:"advanced",def:"Represents a platform component managed by OpenShift (e.g., authentication, dns, ingress, monitoring, network, storage). Each ClusterOperator reports Available, Progressing, and Degraded conditions. A degraded ClusterOperator blocks cluster upgrades. View: oc get clusteroperators",doc:"https://docs.openshift.com/container-platform/4.18/operators/operator-reference.html"},
{term:"MachineConfigOperator",abbr:"MCO",cat:"advanced",def:"Manages OS-level configuration on OpenShift nodes. Applies MachineConfigs to nodes by draining, rebooting with the new config, and uncordoning. Provides in-place OS updates without replacing nodes. Critical for managing CoreOS (RHCOS) node configuration.",doc:"https://docs.openshift.com/container-platform/4.18/architecture/control-plane.html#machine-config-operator_control-plane"},
{term:"MachineConfig",abbr:"MC",cat:"advanced",def:"Defines OS-level configuration for OpenShift nodes: systemd units, kernel arguments, files to write, SSH keys, and container runtime settings. MachineConfigs are merged (rendered) based on which MachineConfigPool selects them. Never edit the rendered config directly.",doc:"https://docs.openshift.com/container-platform/4.18/post_installation_configuration/machine-configuration-tasks.html"},
{term:"MachineConfigPool",abbr:"MCP",cat:"advanced",def:"Groups nodes that share the same MachineConfig. Default pools: master (control plane) and worker. Custom pools allow different OS configs for different node roles (e.g., gpu, infra). A pool's nodes are updated one at a time during a rolling config update.",doc:"https://docs.openshift.com/container-platform/4.18/post_installation_configuration/machine-configuration-tasks.html#understanding-the-machine-config-pool-update-process_post-install-machine-configuration-tasks"},
{term:"KubeletConfig",cat:"advanced",def:"An MCO CRD that allows customizing kubelet configuration (via kubelet.conf) for a MachineConfigPool. Use cases: changing eviction thresholds, increasing max pods per node, setting CPU manager policy, configuring topology manager. Changes trigger a rolling node reboot.",doc:"https://docs.openshift.com/container-platform/4.18/nodes/nodes/nodes-nodes-managing.html"},
{term:"ContainerRuntimeConfig",cat:"advanced",def:"An MCO CRD for customizing the CRI-O container runtime configuration per MachineConfigPool. Use cases: changing the default pull policy, enabling registries, setting log size limits, configuring pids-limit. Applied via MachineConfig — triggers node reboot.",doc:"https://docs.openshift.com/container-platform/4.18/post_installation_configuration/machine-configuration-tasks.html"},
{term:"FeatureGate",cat:"advanced",def:"A cluster-scoped singleton that enables/disables technology preview and experimental Kubernetes/OpenShift features. The TechPreviewNoUpgrade FeatureSet enables tech preview features but locks the cluster against upgrades. View: oc get featuregate",doc:"https://docs.openshift.com/container-platform/4.18/nodes/clusters/nodes-cluster-enabling-features.html"},
{term:"PerformanceProfile",cat:"advanced",def:"A CRD from the Node Tuning Operator that configures a node for low-latency, real-time workloads. Enables CPU pinning (isolated CPUs), huge pages, NUMA topology awareness, and disables CPU power management. Required for telco/NFV workloads.",doc:"https://docs.openshift.com/container-platform/4.18/scalability_and_performance/cnf-create-performance-profiles.html"},
{term:"TunedProfile",cat:"advanced",def:"Configures kernel and OS tuning parameters on nodes via the Node Tuning Operator (based on the tuned daemon). Applies sysctl settings, disk scheduler, CPU frequency scaling, and network buffer sizes. OpenShift ships many built-in profiles; custom profiles can be created.",doc:"https://docs.openshift.com/container-platform/4.18/nodes/nodes/nodes-node-tuning-operator.html"},
{term:"Infrastructure",cat:"advanced",def:"A cluster-scoped singleton (cluster) describing the infrastructure platform (AWS, GCP, Azure, vSphere, bare metal, None). Contains API server URL, ingress domain, cloud region/zone info. Used by operators to make platform-specific decisions. View: oc get infrastructure cluster -o yaml",doc:"https://docs.openshift.com/container-platform/4.18/installing/overview/index.html"},
{term:"Proxy",cat:"advanced",def:"A cluster-scoped singleton configuring the HTTP/HTTPS proxy and no-proxy list for the cluster. When set, OpenShift operators and build pods use these proxy settings. Essential for air-gapped or corporate proxy environments. View: oc get proxy cluster -o yaml",doc:"https://docs.openshift.com/container-platform/4.18/networking/enable-cluster-wide-proxy.html"},
{term:"APIServer",cat:"advanced",def:"A cluster-scoped singleton (cluster) for configuring the Kubernetes/OpenShift API server: TLS ciphers, additional serving certificates, client CA bundles, and audit logging policy. Managed by the kube-apiserver cluster operator. View: oc get apiserver cluster -o yaml",doc:"https://docs.openshift.com/container-platform/4.18/security/tls-security-profiles.html"},
{term:"Authentication",cat:"advanced",def:"A cluster-scoped singleton configuring the identity providers (LDAP, GitHub, OIDC, HTPasswd) for OpenShift login, the OAuth server endpoint, and token lifetimes. View: oc get authentication cluster -o yaml. Edit via: oc edit oauth cluster",doc:"https://docs.openshift.com/container-platform/4.18/authentication/understanding-authentication.html"},
{term:"etcd",cat:"advanced",def:"The distributed key-value store that is the backing store for all Kubernetes cluster data. In OpenShift, etcd runs as a static pod on each control plane node. Back up etcd regularly. The etcd operator manages health, certificates, and cluster membership. View: oc get etcd -o yaml",doc:"https://docs.openshift.com/container-platform/4.18/backup_and_restore/control_plane_backup_and_restore/backing-up-etcd.html"},
{term:"TopologySpreadConstraint",cat:"advanced",def:"Specifies how to spread pods across topology domains (zones, nodes, racks) to achieve high availability and even resource utilization. More powerful than pod anti-affinity — controls maximum skew (pod count difference) between domains. Set at pod template level.",doc:"https://kubernetes.io/docs/concepts/scheduling-eviction/topology-spread-constraints/"},
{term:"NodeFeatureDiscovery",cat:"advanced",def:"An operator that detects hardware and software features on nodes (CPU flags, GPU presence, NUMA topology, kernel version) and exposes them as node labels. Enables workloads to request specific hardware capabilities via nodeSelector without manual node labeling.",doc:"https://docs.openshift.com/container-platform/4.18/hardware_enablement/psap-node-feature-discovery-operator.html"},
{term:"Knative Serving",cat:"advanced",def:"Part of OpenShift Serverless (based on Knative). Enables scale-to-zero deployments — pods are created on demand when requests arrive and terminated when idle. Traffic is managed via Revisions and Routes. The Knative Serving operator manages the installation.",doc:"https://docs.openshift.com/container-platform/4.18/serverless/about/about-serverless.html"},
{term:"Kiali",cat:"advanced",def:"The Service Mesh observability console. Provides a real-time topology graph of services and their traffic, health indicators, and configuration validation for Istio resources. Installed as part of OpenShift Service Mesh. Access via its Route in the istio-system namespace.",doc:"https://kiali.io/"},
// ── Networking: Multus / SR-IOV / NAD ────────────────────────────────────────
{term:"NetworkAttachmentDefinition",abbr:"NAD",cat:"networking",def:"A CRD (from the k8s.cni.cncf.io API group) that defines an additional network interface to attach to a pod. Created by the Multus CNI meta-plugin. The pod references a NAD via the k8s.v1.cni.cncf.io/networks annotation. Used for SR-IOV, macvlan, and other secondary networks alongside the primary pod network.",doc:"https://docs.openshift.com/container-platform/4.18/networking/multiple_networks/understanding-multiple-networks.html"},
{term:"Multus CNI",cat:"networking",def:"A meta CNI plugin that enables attaching multiple network interfaces to a pod. Acts as a 'CNI multiplexer' — it calls the primary CNI (OVN-Kubernetes) for the default interface and additional CNI plugins (macvlan, ipvlan, SR-IOV) for secondary interfaces defined by NADs. Ships as a DaemonSet in openshift-multus namespace.",doc:"https://docs.openshift.com/container-platform/4.18/networking/multiple_networks/understanding-multiple-networks.html"},
{term:"SR-IOV",abbr:"Single Root I/O Virtualization",cat:"networking",def:"A PCIe hardware feature that allows a single physical NIC to present multiple virtual functions (VFs) directly to pods, bypassing the kernel network stack. Achieves near line-rate throughput and microsecond latency. Managed by the SR-IOV Network Operator via SriovNetworkNodePolicy and SriovNetwork CRDs.",doc:"https://docs.openshift.com/container-platform/4.18/networking/hardware_networks/about-sriov.html"},
{term:"SriovNetworkNodePolicy",cat:"networking",def:"A CRD that configures SR-IOV VFs on a specific node or group of nodes. Specifies the NIC device selector, number of VFs, driver (netdevice or vfio-pci for DPDK), and the resource name exposed to the kubelet. Changes trigger a node drain and reboot.",doc:"https://docs.openshift.com/container-platform/4.18/networking/hardware_networks/configuring-sriov-device.html"},
{term:"SriovNetwork",cat:"networking",def:"A CRD that creates a NetworkAttachmentDefinition backed by an SR-IOV VF. References a SriovNetworkNodePolicy resource and defines VLAN, QoS, and IP AM configuration. Pods request the VF via the NAD annotation.",doc:"https://docs.openshift.com/container-platform/4.18/networking/hardware_networks/configuring-sriov-net-attach.html"},
{term:"IPAM",abbr:"IP Address Management",cat:"networking",def:"The component responsible for assigning IP addresses to additional pod network interfaces (from NADs). IPAM plugins include: static (fixed IP), whereabouts (cluster-wide IPAM with no DHCP), host-local (per-node subnet), and DHCP. Configured within the NAD spec.",doc:"https://docs.openshift.com/container-platform/4.18/networking/multiple_networks/understanding-multiple-networks.html"},
{term:"bridge binding",cat:"networking",def:"A KubeVirt VM network binding mode that connects the VM's NIC directly to a Linux bridge on the node via a tap device. The VM gets a MAC address visible on the bridge — identical to a physical machine on that network segment. Requires a NetworkAttachmentDefinition using the bridge CNI plugin.",doc:"https://docs.openshift.com/container-platform/4.18/virt/vm_networking/virt-connecting-vm-to-linux-bridge.html"},
{term:"masquerade binding",cat:"networking",def:"The default KubeVirt VM network binding mode for the pod network. The VM's traffic is NAT-ed through the virt-launcher pod's IP using iptables masquerade rules. The VM sees a private IP; external traffic reaches it through the pod IP. Recommended for VMs that only need pod-network connectivity.",doc:"https://docs.openshift.com/container-platform/4.18/virt/vm_networking/virt-connecting-vm-to-default-pod-network.html"},
{term:"live migration network",cat:"networking",def:"A dedicated secondary network interface used exclusively for VM live-migration traffic, keeping migration bandwidth separate from workload traffic. Configured by setting the migration.network in the HyperConverged CR and attaching a NAD for the migration network. Prevents migration from saturating the primary NIC.",doc:"https://docs.openshift.com/container-platform/4.18/virt/live_migration/virt-configuring-live-migration.html"},
{term:"secondary network",cat:"networking",def:"An additional network interface attached to a VM (or pod) beyond the default pod network. Defined via a NetworkAttachmentDefinition and referenced in the VM spec under networks[]. Common use cases: storage traffic isolation, direct L2 connectivity, SR-IOV high-performance data planes.",doc:"https://docs.openshift.com/container-platform/4.18/virt/vm_networking/virt-connecting-vm-to-secondary-udn.html"},
// ── OpenShift Data Foundation (ODF) ──────────────────────────────────────────
{term:"OpenShift Data Foundation",abbr:"ODF",cat:"odf",def:"Red Hat's integrated software-defined storage solution for OpenShift, based on Rook-Ceph and NooBaa. Provides block (RBD), file (CephFS), and object (S3-compatible via NooBaa) storage in a single operator. Enables internal PV provisioning without external storage infrastructure.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation"},
{term:"StorageCluster",cat:"odf",def:"The top-level ODF CRD (ocs.openshift.io/v1) that defines the Ceph cluster configuration: storage devices (local disks or PVCs), replica count, encryption, and network. Creating a StorageCluster triggers ODF to deploy Ceph monitors, OSDs, MGR, and NooBaa. One StorageCluster per OCP cluster.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation"},
{term:"CephCluster",cat:"odf",def:"The Rook-Ceph CRD that models the Ceph cluster configuration: MONs (monitors), OSDs (object storage daemons), MGR (manager), MDS (metadata for CephFS), and RGW (RADOS Gateway for object). ODF manages this automatically via the StorageCluster — do not edit directly.",doc:"https://rook.io/docs/rook/latest/CRDs/Cluster/ceph-cluster-crd/"},
{term:"Rook",cat:"odf",def:"A Cloud Native Computing Foundation (CNCF) project that manages Ceph (and other storage systems) as a Kubernetes operator. ODF uses Rook-Ceph as its storage engine. Rook deploys Ceph components as pods and manages day-2 operations (expansion, recovery, upgrades) via CRDs.",doc:"https://rook.io/"},
{term:"Ceph RBD",abbr:"RADOS Block Device",cat:"odf",def:"Ceph's block storage backend. Provides ReadWriteOnce (RWO) PersistentVolumes for databases and stateful apps. Each PV maps to a Ceph image (a raw block device stored as objects in a Ceph pool). The ocs-storagecluster-ceph-rbd StorageClass provisions RBD PVs in ODF.",doc:"https://docs.ceph.com/en/latest/rbd/"},
{term:"CephFS",cat:"odf",def:"Ceph's POSIX-compliant distributed filesystem. Provides ReadWriteMany (RWX) PersistentVolumes — multiple pods can mount the same PV simultaneously. Built on Ceph RADOS with a metadata layer (MDS). The ocs-storagecluster-cephfs StorageClass provisions CephFS PVs in ODF.",doc:"https://docs.ceph.com/en/latest/cephfs/"},
{term:"ObjectBucketClaim",abbr:"OBC",cat:"odf",def:"A CRD (objectbucket.io/v1alpha1) for requesting an S3-compatible object storage bucket from NooBaa or another object store. Like a PVC but for buckets. When created, ODF provisions a bucket and creates a ConfigMap (endpoint/bucket name) and a Secret (access key/secret) with the same name.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation/4.18/html/managing_hybrid_and_multicloud_resources/object-bucket-claim"},
{term:"NooBaa",cat:"odf",def:"The multicloud object gateway component of ODF. Provides an S3-compatible endpoint that can federate object storage across AWS S3, Azure Blob, GCS, and local Ceph RGW. Used by ODF to serve ObjectBucketClaims. Managed via BackingStore and BucketClass CRDs.",doc:"https://www.noobaa.io/"},
{term:"BackingStore",cat:"odf",def:"A NooBaa CRD defining an underlying storage target for object data: Ceph RGW, AWS S3, Azure Blob, GCS, or local PVC. NooBaa policies (BucketClasses) spread/mirror/tier data across BackingStores. Multiple BackingStores enable multicloud object storage federation.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation"},
{term:"BucketClass",cat:"odf",def:"A NooBaa CRD defining the data placement policy for object buckets: spread (distribute across BackingStores), mirror (replicate to all), or tiering (move data between tiers based on age). ObjectBucketClaims reference a BucketClass to inherit its data placement policy.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation"},
{term:"MirrorPeer",cat:"odf",def:"A CRD used in ODF Regional-DR (Disaster Recovery) to establish a peering relationship between two ODF clusters. Once MirrorPeers are exchanged, Ceph RBD mirroring and CephFS snapshot mirroring can be configured. Required for Metro-DR and Regional-DR topologies.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation/4.18/html/configuring_openshift_data_foundation_disaster_recovery_for_openshift_workloads"},
{term:"VolumeReplicationGroup",abbr:"VRG",cat:"odf",def:"A CRD (ramendr.openshift.io) used by ODF DR that groups PVCs for replication. A VRG in Primary mode replicates PVs to a secondary site; in Secondary mode it restores them. Managed by the Ramen Disaster Recovery orchestrator as part of Regional-DR failover.",doc:"https://access.redhat.com/documentation/en-us/red_hat_openshift_data_foundation"},
{term:"CephFS Subvolume",cat:"odf",def:"The Ceph storage unit backing a CephFS PersistentVolume. Each PVC provisioned via the CephFS StorageClass maps to a Ceph subvolume in a dedicated CephFS volume (filesystem). Subvolume groups allow quota management and snapshot-based backup.",doc:"https://docs.ceph.com/en/latest/cephfs/fs-volumes/"},
// ── Backup & Restore (OADP / Velero) ─────────────────────────────────────────
{term:"OpenShift API for Data Protection",abbr:"OADP",cat:"backup",def:"Red Hat's backup and restore operator for OpenShift, built on Velero. Installs and manages Velero, Restic/Kopia, and the DataProtectionApplication CRD. OADP abstracts object store and snapshot provider configuration. Supports backup to S3-compatible stores (AWS, MinIO, NooBaa, ODF).",doc:"https://docs.openshift.com/container-platform/4.18/backup_and_restore/application_backup_and_restore/oadp-intro.html"},
{term:"DataProtectionApplication",abbr:"DPA",cat:"backup",def:"The top-level OADP CRD that configures the entire backup stack: which plugins to enable (aws, gcp, csi), the BackupStorageLocation, VolumeSnapshotLocation, and whether Restic/Kopia node-agent is enabled. One DPA per cluster triggers OADP to deploy Velero.",doc:"https://docs.openshift.com/container-platform/4.18/backup_and_restore/application_backup_and_restore/installing/about-installing-oadp.html"},
{term:"Velero",cat:"backup",def:"The open-source backup and restore tool that OADP is built on. Backs up Kubernetes objects (as JSON to object storage) and optionally PV data (via CSI snapshots or Restic/Kopia file-level backup). Runs as a pod in the openshift-adp namespace. Manages Backup, Restore, and Schedule CRDs.",doc:"https://velero.io/"},
{term:"BackupStorageLocation",abbr:"BSL",cat:"backup",def:"A Velero/OADP CRD defining where backup data (Kubernetes object JSON) is stored. Typically an S3-compatible bucket with credentials, prefix, and region. Multiple BSLs can coexist — each Backup references a BSL. The default BSL is used when not specified.",doc:"https://velero.io/docs/latest/api-types/backupstoragelocation/"},
{term:"VolumeSnapshotLocation",abbr:"VSL",cat:"backup",def:"A Velero/OADP CRD defining where CSI volume snapshots are stored. References the CSI driver provider (aws-ebs, gcp-pd, ceph-rbd) and configuration. Used when backup.spec.snapshotVolumes is true. Not needed when using Restic/Kopia for PV backup.",doc:"https://velero.io/docs/latest/api-types/volumesnapshotlocation/"},
{term:"Backup",cat:"backup",def:"A Velero CRD representing a single backup operation: which namespaces/resources to include/exclude, TTL, whether to snapshot volumes, and which BSL to use. Status phases: New, FailedValidation, InProgress, WaitingForPluginOperations, Completed, Failed, PartiallyFailed, Deleting.",doc:"https://velero.io/docs/latest/api-types/backup/"},
{term:"Restore",cat:"backup",def:"A Velero CRD that restores Kubernetes objects and PV data from a Backup. Can restore to a different namespace (namespaceMapping), exclude resources, or restore only specific labels. Status: New, FailedValidation, InProgress, WaitingForPluginOperations, Completed, Failed, PartiallyFailed.",doc:"https://velero.io/docs/latest/api-types/restore/"},
{term:"Schedule",cat:"backup",def:"A Velero CRD that creates recurring Backups on a cron schedule. Combines a Backup spec with a cron expression. View with: oc get schedule -n openshift-adp. Each scheduled run creates a timestamped Backup object.",doc:"https://velero.io/docs/latest/api-types/schedule/"},
{term:"Kopia",cat:"backup",def:"The file-level backup engine used by OADP 1.2+ to back up PV data that cannot be snapshotted via CSI. Replaces Restic as the default node agent. Kopia deduplicates and compresses data before uploading to the BSL. Runs as a DaemonSet (node-agent) on all nodes.",doc:"https://kopia.io/"},
{term:"DeleteBackupRequest",cat:"backup",def:"A Velero CRD that triggers deletion of a Backup and all its associated data (object storage files and CSI snapshots). Used for manual cleanup or when TTL expires. More reliable than deleting the Backup object directly.",doc:"https://velero.io/docs/latest/api-types/deletebackuprequest/"},
// ── Virtualization (OpenShift Virtualization / KubeVirt) ─────────────────────
{term:"OpenShift Virtualization",cat:"virt",def:"An OCP add-on operator (based on KubeVirt) that enables running virtual machines alongside containers on the same OpenShift cluster. VMs are first-class Kubernetes objects — scheduled, networked, and managed via standard Kubernetes APIs. Requires hardware virtualization (Intel VT-x / AMD-V) on nodes.",doc:"https://docs.openshift.com/container-platform/4.18/virt/about_virt/about-virt.html"},
{term:"KubeVirt",cat:"virt",def:"The upstream CNCF project that OpenShift Virtualization is based on. Extends Kubernetes with VirtualMachine and VirtualMachineInstance CRDs. Each VMI runs as a pod containing a virt-launcher container wrapping a QEMU/KVM process. VMs are scheduled by the standard Kubernetes scheduler.",doc:"https://kubevirt.io/"},
{term:"HyperConverged",abbr:"HCO",cat:"virt",def:"The top-level OpenShift Virtualization CRD (hco.kubevirt.io) that manages the entire virtualization stack: KubeVirt, CDI, NetworkAddonsOperator, SSP Operator, and HostPath Provisioner. Creating a HyperConverged CR deploys all virtualization components. One per cluster.",doc:"https://docs.openshift.com/container-platform/4.18/virt/install/installing-virt.html"},
{term:"VirtualMachine",abbr:"VM",cat:"virt",def:"A KubeVirt CRD (kubevirt.io/v1) representing a virtual machine definition — its CPU, memory, disks, network interfaces, and running state. Like a Deployment for VMs: manages the lifecycle of a VirtualMachineInstance. A VM can be stopped without deleting the definition.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"VirtualMachineInstance",abbr:"VMI",cat:"virt",def:"A KubeVirt CRD representing a running VM (equivalent to a Pod for containers). Created automatically when a VirtualMachine is started. Contains the VM's runtime state, IP address, and virt-launcher pod reference. Deleting the VMI stops the VM but preserves the VirtualMachine definition.",doc:"https://docs.openshift.com/container-platform/4.18/virt/about_virt/about-virt.html"},
{term:"DataVolume",abbr:"DV",cat:"virt",def:"A CDI CRD (cdi.kubevirt.io/v1beta1) that orchestrates importing, uploading, or cloning disk images into PersistentVolumeClaims for VM use. Sources: HTTP URL, registry (container disk), S3, PVC clone, blank. Replaces manual PVC creation + import job workflows.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-using-data-volumes-with-vms.html"},
{term:"ContainerizedDataImporter",abbr:"CDI",cat:"virt",def:"A KubeVirt sub-project (and OpenShift Virtualization component) that imports, uploads, and clones VM disk images into PVCs. Manages DataVolumes. Runs as the cdi-operator in the cdi namespace. Enables cloning PVCs across namespaces for VM templating workflows.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-using-data-volumes-with-vms.html"},
{term:"VirtualMachineInstanceMigration",cat:"virt",def:"A KubeVirt CRD that triggers a live migration of a running VMI from one node to another without downtime. Requires a ReadWriteMany (RWX) storage volume (CephFS or NFS). Created manually or automatically by the eviction strategy when a node is drained.",doc:"https://docs.openshift.com/container-platform/4.18/virt/live_migration/virt-about-live-migration.html"},
{term:"Live Migration",cat:"virt",def:"The process of moving a running VM from one OpenShift node to another without stopping the VM or losing the network connection. Requires RWX PVCs, compatible CPU features across nodes, and sufficient resources on the target node. Triggered via VirtualMachineInstanceMigration CR.",doc:"https://docs.openshift.com/container-platform/4.18/virt/live_migration/virt-about-live-migration.html"},
{term:"InstanceType",cat:"virt",def:"A KubeVirt CRD (VirtualMachineInstancetype) that predefines VM resource sizing (CPU, memory) separate from the VM definition — similar to AWS instance types (t3.medium). Cluster-scoped (VirtualMachineClusterInstancetype) or namespace-scoped. Simplifies VM templating and enforces resource standards.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"VirtualMachinePreference",cat:"virt",def:"A KubeVirt CRD that defines preferred (non-binding) VM settings: OS disk bus, preferred network interface model (virtio, e1000), CPU features, and machine type. Referenced by a VirtualMachine alongside an InstanceType. Cluster-scoped or namespace-scoped.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"VirtualMachineClusterInstancetype",cat:"virt",def:"The cluster-scoped variant of VirtualMachineInstancetype (instancetype.kubevirt.io). Predefines CPU and memory sizing available to VMs across all namespaces. Red Hat ships a set of common-instancetypes (u1.micro, u1.small, etc.) as VirtualMachineClusterInstancetype objects. Reference with: instancetype.name in the VM spec.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"VirtualMachineClusterPreference",cat:"virt",def:"The cluster-scoped variant of VirtualMachinePreference (instancetype.kubevirt.io). Defines preferred settings (disk bus, NIC model, machine type) available to VMs in any namespace. Red Hat ships common-preferences (rhel.9, fedora, windows.2k22, etc.) as VirtualMachineClusterPreference objects.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"VirtualMachineInstanceReplicaSet",abbr:"VMIRS",cat:"virt",def:"A KubeVirt CRD (kubevirt.io/v1) that maintains a desired number of identical running VMIs — the VM equivalent of a ReplicaSet. Rarely used directly; VirtualMachinePool is preferred for most scale-out VM scenarios. oc get vmirs lists all replica sets.",doc:"https://kubevirt.io/api-reference/main/definitions.html#_v1_virtualmachineinstancereplicaset"},
{term:"VirtualMachinePool",cat:"virt",def:"A KubeVirt CRD that manages a pool of identical VirtualMachines (not VMIs directly), providing scale-out and self-healing for stateless VMs. Like a Deployment but for VMs. Each pool member has its own persistent VirtualMachine object. oc get vmpool lists pools.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/virt-create-vms.html"},
{term:"VirtualMachineSnapshot",cat:"virt",def:"A snapshot.kubevirt.io CRD that captures a point-in-time snapshot of a VirtualMachine (disks + configuration). Requires a VolumeSnapshotClass backed by a CSI driver that supports snapshots (e.g., Ceph RBD). Used as the source for VirtualMachineRestore. oc get vmsnapshot.",doc:"https://docs.openshift.com/container-platform/4.18/virt/backup_restore/virt-managing-vm-snapshots.html"},
{term:"VirtualMachineSnapshotContent",cat:"virt",def:"The low-level snapshot.kubevirt.io object that stores the actual snapshot data references (VolumeSnapshot CRs) created by a VirtualMachineSnapshot. Managed automatically — do not edit directly. Analogous to PersistentVolume backing a PVC.",doc:"https://docs.openshift.com/container-platform/4.18/virt/backup_restore/virt-managing-vm-snapshots.html"},
{term:"VirtualMachineRestore",cat:"virt",def:"A snapshot.kubevirt.io CRD that restores a VirtualMachine to the state captured in a VirtualMachineSnapshot. The VM must be stopped before restoring. Creates new PVCs from the snapshot content and replaces the VM's disk references. oc get vmrestore.",doc:"https://docs.openshift.com/container-platform/4.18/virt/backup_restore/virt-managing-vm-snapshots.html"},
{term:"VirtualMachineExport",cat:"virt",def:"An export.kubevirt.io CRD that exposes a VM's disk data (from a stopped VM, snapshot, or PVC) as a temporary HTTP endpoint for download. Enables extracting disk images outside the cluster without live migration. A token-secured URL is generated for the export.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/virt-exporting-vms.html"},
{term:"VirtualMachineClone",cat:"virt",def:"A clone.kubevirt.io CRD that creates a full copy of a VirtualMachine into a target namespace, stripping identity-specific data (MAC addresses, SSH keys, tokens) via a customization policy. Enables self-service VM cloning across namespaces. oc get vmclone.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/virt-cloning-vms.html"},
{term:"MigrationPolicy",cat:"virt",def:"A migrations.kubevirt.io CRD that defines per-workload live-migration parameters: bandwidth limit, completion timeout, parallelism, and auto-convergence settings. Policies are matched to VMIs via label selectors, overriding the cluster-wide HyperConverged migration configuration.",doc:"https://docs.openshift.com/container-platform/4.18/virt/live_migration/virt-configuring-live-migration.html"},
{term:"CDIConfig",cat:"virt",def:"The cluster-scoped singleton CRD (cdi.kubevirt.io) that holds CDI's runtime configuration: scratch space storage class, default proxy settings, filesystem overhead, and upload proxy URL. One CDIConfig exists per cluster and is managed by the CDI operator.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-using-data-volumes-with-vms.html"},
{term:"StorageProfile",cat:"virt",def:"A CDI CRD (cdi.kubevirt.io) that records the recommended access modes and volume modes for a given StorageClass. CDI automatically creates a StorageProfile for each StorageClass. VM disk import and cloning use StorageProfile settings to select optimal PVC parameters.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-storage-config-overview.html"},
{term:"DataSource",cat:"virt",def:"A CDI CRD (cdi.kubevirt.io) that points to a golden PVC or VolumeSnapshot used as the source for cloning new VM disks. DataSources are namespace-scoped and enable automatic golden-image refresh: when the source image is updated, the DataSource is updated and downstream VMs can be re-cloned.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"ObjectTransfer",cat:"virt",def:"A CDI CRD (cdi.kubevirt.io) that performs a namespace-to-namespace transfer of a DataVolume or PVC without copying the underlying data. Uses a token-based handshake to claim the PV in the destination namespace. Enables zero-copy VM migrations between namespaces.",doc:"https://github.com/kubevirt/containerized-data-importer/blob/main/doc/datavolume-transfer.md"},
{term:"SSP Operator",abbr:"SSP",cat:"virt",def:"The Scheduling, Scale and Performance Operator (ssp.kubevirt.io). A component of the HyperConverged stack that manages VM Templates, the common-instancetypes and common-preferences bundles, and the Template Validator webhook. Ensures template correctness and ships Red Hat's default VM templates.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"HostPathProvisioner",cat:"virt",def:"A KubeVirt component (hostpathprovisioner.kubevirt.io) that dynamically provisions local-storage PVs from a node's filesystem path. Useful for development clusters and single-node OpenShift (SNO) where shared storage is unavailable. Managed by the HyperConverged operator.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-storage-config-overview.html"},
{term:"cluster-network-addons-operator",cat:"virt",def:"A HyperConverged sub-component (NetworkAddonsOperator) that deploys and manages additional virt-specific networking components: the bridge CNI plugin, the kubemacpool MAC address manager, and the ovs-cni plugin for Open vSwitch bridges. Required for VM bridge and SR-IOV network bindings.",doc:"https://github.com/kubevirt/cluster-network-addons-operator"},
{term:"golden image",cat:"virt",def:"A pre-configured, patched VM disk image stored as a PVC or DataSource that serves as the authoritative source for cloning new VM disks. OpenShift Virtualization automatically maintains golden images for supported OS variants (RHEL, Fedora, Windows) in the openshift-virtualization-os-images namespace.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/creating_vms_rh/virt-creating-vms-from-rh-images-overview.html"},
{term:"cloud-init",cat:"virt",def:"A cross-platform guest initialization framework that runs scripts and applies configuration on first VM boot: setting hostname, users, SSH keys, network config, and running arbitrary commands. KubeVirt VMs accept cloud-init data via the cloudInitNoCloud or cloudInitConfigDrive disk source in the VM spec.",doc:"https://docs.openshift.com/container-platform/4.18/virt/virtual_machines/virt-accessing-vm-consoles.html"},
{term:"disk image",cat:"virt",def:"A file that contains the complete contents of a virtual disk. KubeVirt supports importing disk images from HTTP servers, container registries (as container disks), or S3. Common formats: qcow2 (copy-on-write, compressed), raw (flat binary). Disk images are imported into PVCs via DataVolumes.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-using-data-volumes-with-vms.html"},
{term:"qcow2",cat:"virt",def:"QEMU Copy-On-Write v2 — the standard VM disk image format for KVM/QEMU. Supports thin provisioning (only stores written blocks), snapshots, compression, and encryption within the image file. CDI can import qcow2 images directly into PVCs. Preferred format for distributing VM base images.",doc:"https://qemu.readthedocs.io/en/latest/system/qemu-block-drivers.html#qcow2-imageformat"},
{term:"raw image",cat:"virt",def:"A flat binary disk image with no metadata or compression — every byte maps 1:1 to disk content. Maximum performance (no format overhead) but no built-in snapshots or compression. CDI can import raw images; they are stored as raw in the PVC. Often used for production data disks.",doc:"https://docs.openshift.com/container-platform/4.18/virt/storage/virt-using-data-volumes-with-vms.html"},
// ── Multi-Cluster / ACM ───────────────────────────────────────────────────────
{term:"Advanced Cluster Management",abbr:"ACM",cat:"multicluster",def:"Red Hat Advanced Cluster Management for Kubernetes. Provides a central hub for managing a fleet of OpenShift and Kubernetes clusters: cluster lifecycle (create, import, destroy), policy enforcement, application delivery (GitOps), and observability across all clusters.",doc:"https://access.redhat.com/documentation/en-us/red_hat_advanced_cluster_management_for_kubernetes"},
{term:"MultiClusterHub",abbr:"MCH",cat:"multicluster",def:"The top-level ACM CRD that deploys the entire ACM hub stack on the hub cluster. Manages cluster registry, policy engine, search, application lifecycle, and observability components. One MultiClusterHub per hub cluster. Status must be 'Running' before importing managed clusters.",doc:"https://access.redhat.com/documentation/en-us/red_hat_advanced_cluster_management_for_kubernetes"},
{term:"ManagedCluster",cat:"multicluster",def:"An ACM CRD representing an imported or created cluster managed by the hub. Contains cluster metadata (labels, taints), capacity, and conditions (HubAcceptedManagedCluster, ManagedClusterConditionAvailable). Labels on ManagedClusters drive Placement decisions for policy and app delivery.",doc:"https://access.redhat.com/documentation/en-us/red_hat_advanced_cluster_management_for_kubernetes"},
{term:"ManifestWork",cat:"multicluster",def:"An ACM CRD on the hub that defines Kubernetes resources to be applied on a specific managed cluster. The work-agent on the managed cluster watches for ManifestWork objects addressed to it and applies them. The primary delivery mechanism for ACM application subscriptions and policies.",doc:"https://open-cluster-management.io/concepts/manifestwork/"},
{term:"Placement",cat:"multicluster",def:"An ACM/OCM CRD that selects a set of ManagedClusters based on label selectors, cluster conditions, resource capacity, and tolerations. Used by PolicySets and ApplicationSets to determine which clusters receive workloads or policies. Replaces the older PlacementRule CRD.",doc:"https://open-cluster-management.io/concepts/placement/"},
{term:"Policy",cat:"multicluster",def:"An ACM CRD defining a governance rule to enforce across managed clusters: configuration compliance (e.g., must have a LimitRange), security posture (e.g., no privileged pods), or informational checks. Policies have inform (report only) or enforce (auto-remediate) modes. Violations show in the ACM governance dashboard.",doc:"https://access.redhat.com/documentation/en-us/red_hat_advanced_cluster_management_for_kubernetes/2.11/html/governance/governance"},
{term:"ClusterSet",cat:"multicluster",def:"An ACM grouping of ManagedClusters for RBAC and Placement purposes. A ClusterSetBinding in a namespace grants access to clusters in the set for application placement. Enables multi-tenancy — different teams can manage different cluster sets without seeing each other's clusters.",doc:"https://open-cluster-management.io/concepts/managedclusterset/"},
{term:"MultiClusterObservability",cat:"multicluster",def:"An ACM CRD that deploys the observability stack: Thanos-based metrics aggregation from all managed clusters into a central S3 store, plus a Grafana instance on the hub with pre-built dashboards for fleet-wide monitoring. Requires an S3-compatible BackingStore.",doc:"https://access.redhat.com/documentation/en-us/red_hat_advanced_cluster_management_for_kubernetes/2.11/html/observability/observing-environments-intro"},
{term:"ApplicationSet",cat:"multicluster",def:"An ArgoCD/OpenShift GitOps CRD that generates multiple ArgoCD Applications from a single template — one per matched cluster or environment. Integrates with ACM Placement to deploy the same app to all clusters in a ClusterSet. The hub-of-hubs GitOps delivery pattern for fleet management.",doc:"https://argocd-applicationset.readthedocs.io/"},
// ── Acronyms ─────────────────────────────────────────────────────────────────
{term:"OCP",abbr:"OpenShift Container Platform",cat:"acronym",def:"Red Hat's enterprise Kubernetes distribution. Adds developer tooling (S2I, ImageStreams, Routes, BuildConfigs), enterprise security (SCC, OAuth), an operator ecosystem (OLM, OperatorHub), and a managed monitoring/logging stack on top of upstream Kubernetes."},
{term:"K8s",abbr:"Kubernetes",cat:"acronym",def:"Short for Kubernetes — the 8 letters between K and s. The open-source container orchestration system originally developed by Google. OpenShift (OCP) is built on top of Kubernetes and contributes back to the project."},
{term:"RHCOS",abbr:"Red Hat CoreOS",cat:"acronym",def:"The immutable, container-optimized operating system used on OpenShift nodes. Based on RHEL CoreOS. Managed entirely by the Machine Config Operator (MCO) — not manually configured like traditional RHEL. Updates are applied as atomic image replacements."},
{term:"UBI",abbr:"Universal Base Image",cat:"acronym",def:"Red Hat's freely redistributable container base images. Three flavors: ubi9 (full), ubi9-minimal (microdnf), ubi9-micro (no package manager). Recommended as the base for all container images running on OpenShift. Receives security patches on Red Hat's schedule."},
{term:"CNI",abbr:"Container Network Interface",cat:"acronym",def:"The plugin API for Kubernetes networking. CNI plugins implement pod network creation and deletion. OpenShift 4.x defaults to OVN-Kubernetes as the CNI plugin. Others: Calico, Cilium, OpenShift SDN (legacy). Configured during cluster installation."},
{term:"CRI",abbr:"Container Runtime Interface",cat:"acronym",def:"The gRPC API between the kubelet and container runtime. Defines how kubelet requests container operations (create, start, stop, delete). OpenShift 4.x uses CRI-O as the container runtime. Docker support was removed in Kubernetes 1.24."},
{term:"CRI-O",abbr:"CRI + OCI",cat:"acronym",def:"The lightweight container runtime used by OpenShift. Implements the CRI to work with kubelet and uses OCI-compliant runtimes (runc, crun) to run containers. Designed specifically for Kubernetes — no daemon, no docker CLI needed."},
{term:"OCI",abbr:"Open Container Initiative",cat:"acronym",def:"Industry standards body that defines the container image format and runtime specification. An OCI image can run on any OCI-compliant runtime (runc, crun, kata-containers). Docker images are OCI-compliant."},
{term:"RBAC",abbr:"Role-Based Access Control",cat:"acronym",def:"The Kubernetes authorization mechanism that controls who can perform which actions on which resources. Built from Roles/ClusterRoles (what's allowed) and RoleBindings/ClusterRoleBindings (who gets the role). Enabled by default in all Kubernetes clusters."},
{term:"SRE",abbr:"Site Reliability Engineering",cat:"acronym",def:"An engineering discipline applying software engineering principles to operations. SREs manage reliability through SLOs (Service Level Objectives), error budgets, and automated toil elimination. DO180 is targeted at SREs who manage OpenShift clusters."},
{term:"mTLS",abbr:"Mutual TLS",cat:"acronym",def:"TLS authentication in both directions — both client and server present certificates. Used in Service Mesh to encrypt and authenticate all inter-service communication automatically. OpenShift Service Mesh enables mTLS cluster-wide with a policy object."},
{term:"OLM",abbr:"Operator Lifecycle Manager",cat:"acronym",def:"See: Operator Lifecycle Manager. The OpenShift system for installing, updating, and managing the lifecycle of Operators. Manages CatalogSources, Subscriptions, InstallPlans, and CSVs."},
{term:"CVO",abbr:"Cluster Version Operator",cat:"acronym",def:"See: ClusterVersionOperator. The operator that manages OpenShift cluster upgrades. Reads the ClusterVersion object and drives the upgrade process for all cluster operators."},
{term:"MCO",abbr:"Machine Config Operator",cat:"acronym",def:"See: MachineConfigOperator. Manages OS-level node configuration via MachineConfig and MachineConfigPool objects. Controls kernel args, systemd units, and CRI-O configuration."},
{term:"CMO",abbr:"Cluster Monitoring Operator",cat:"acronym",def:"See: Cluster Monitoring Operator. Manages the OpenShift monitoring stack (Prometheus, Alertmanager, Thanos, Grafana). Configured via cluster-monitoring-config ConfigMap in openshift-monitoring."},
{term:"SCC",abbr:"Security Context Constraints",cat:"acronym",def:"See: SecurityContextConstraints. OpenShift's pod security admission system controlling what privileges pods can request. From most to least restrictive: restricted-v2 → nonroot → anyuid → privileged."},
{term:"SDN",abbr:"Software Defined Networking",cat:"acronym",def:"The legacy OpenShift network plugin (OpenShift SDN). Replaced by OVN-Kubernetes in OCP 4.12+ as the default. SDN used VXLAN for pod networking and HostSubnets for node allocation. Migration to OVN-K is supported."},
{term:"OVN",abbr:"Open Virtual Network",cat:"acronym",def:"The network control plane component used by OVN-Kubernetes. Implements virtual L2/L3 networking using OpenFlow rules on Open vSwitch. Provides the logical switching and routing abstractions for Kubernetes pod networking."},
{term:"HAProxy",abbr:"High Availability Proxy",cat:"acronym",def:"The reverse proxy/load balancer used by the OpenShift Ingress Router. Routes HTTP/HTTPS traffic to pods based on Route definitions. Supports WebSocket, HTTP/2, sticky sessions, and health checks. Runs as a DaemonSet in the openshift-ingress namespace."},
{term:"FQDN",abbr:"Fully Qualified Domain Name",cat:"acronym",def:"A complete domain name including all labels from the hostname to the TLD. In Kubernetes: <service>.<namespace>.svc.cluster.local is the FQDN for a Service. OpenShift Routes use a FQDN like app.apps.<cluster-domain>."},
{term:"QoS",abbr:"Quality of Service",cat:"acronym",def:"Kubernetes assigns each pod a QoS class based on resource requests/limits. Guaranteed (requests==limits): never evicted first. Burstable (requests < limits): evicted if node is under pressure. BestEffort (no requests/limits): evicted first. Avoid BestEffort in production."},
{term:"OOM",abbr:"Out of Memory",cat:"acronym",def:"Occurs when a container exceeds its memory limit. The Linux kernel OOM killer terminates the container (exit code 137). The kubelet restarts it based on restartPolicy. Prevent by setting accurate memory limits and readiness probes that fail before OOM."},
{term:"CI/CD",abbr:"Continuous Integration / Continuous Delivery",cat:"acronym",def:"CI: automatically building and testing code on every commit. CD: automatically deploying validated builds to environments. In OpenShift: Tekton Pipelines for CI/CD orchestration, ArgoCD/OpenShift GitOps for continuous delivery via Git."},
{term:"PSA",abbr:"Pod Security Admission",cat:"acronym",def:"See: Pod Security Admission. Kubernetes built-in admission controller enforcing Pod Security Standards via namespace labels. Three profiles: privileged, baseline, restricted. Works alongside OpenShift's SCC system."},
{term:"API",abbr:"Application Programming Interface",cat:"acronym",def:"In the Kubernetes context: the RESTful HTTP interface that all components use to communicate. Every resource (Pod, Service, Deployment) is an API object. The API is versioned (v1, apps/v1, batch/v1). Explore with: oc api-resources"},
{term:"CSI",abbr:"Container Storage Interface",cat:"acronym",def:"The standard API for storage plugins in Kubernetes. CSI drivers implement PV provisioning, attachment, mounting, snapshots, and cloning. OpenShift ships CSI drivers for AWS EBS, GCP PD, Azure Disk, vSphere, and Ceph RBD. Replaced the legacy in-tree storage plugins."},
{term:"HPA",abbr:"HorizontalPodAutoscaler",cat:"acronym",def:"See: HorizontalPodAutoscaler. Scales pod replicas based on CPU/memory utilization or custom metrics. Requires resource requests to be set. Scale-up is fast; scale-down has a 5-minute stabilization window by default."},
{term:"VPA",abbr:"VerticalPodAutoscaler",cat:"acronym",def:"See: VerticalPodAutoscaler. Automatically adjusts CPU/memory requests for containers based on observed usage. Use for right-sizing workloads. Conflicts with HPA on the same metric — use HPA for replicas, VPA for sizing."},
{term:"PDB",abbr:"PodDisruptionBudget",cat:"acronym",def:"See: PodDisruptionBudget. Protects app availability during voluntary disruptions by limiting how many pods can be simultaneously disrupted. Set minAvailable or maxUnavailable. Respected by node drain and cluster upgrades."},
{term:"NFV",abbr:"Network Function Virtualization",cat:"acronym",def:"Replacing traditional network appliances (firewalls, load balancers, routers) with software running on commodity hardware. OpenShift supports NFV workloads via PerformanceProfiles, DPDK, SR-IOV, and real-time kernel configurations."},
{term:"DPDK",abbr:"Data Plane Development Kit",cat:"acronym",def:"A set of libraries for fast packet processing that bypasses the kernel network stack. Used in telco/NFV workloads on OpenShift for high-throughput, low-latency networking. Requires SR-IOV, hugepages, and CPU pinning via PerformanceProfile."},
{term:"NUMA",abbr:"Non-Uniform Memory Access",cat:"acronym",def:"A memory architecture where access time depends on the memory location relative to the processor. On multi-socket servers, accessing remote NUMA node memory is slower. OpenShift Topology Manager can pin pods to a single NUMA node for latency-sensitive workloads."},
{term:"ODF",abbr:"OpenShift Data Foundation",cat:"acronym",def:"See: OpenShift Data Foundation. Red Hat's integrated storage operator providing block (Ceph RBD), file (CephFS), and object (NooBaa) storage for OpenShift clusters. Formerly known as OpenShift Container Storage (OCS)."},
{term:"OCS",abbr:"OpenShift Container Storage",cat:"acronym",def:"The former name for OpenShift Data Foundation (ODF). Rebranded to ODF in OCP 4.9. The operator, APIs, and StorageCluster CRD are unchanged. OCS/ODF terms are used interchangeably in older documentation and support cases."},
{term:"OADP",abbr:"OpenShift API for Data Protection",cat:"acronym",def:"See: OpenShift API for Data Protection. The Red Hat-supported backup operator for OpenShift built on Velero. Manages DataProtectionApplication, Backup, Restore, and Schedule CRDs. Deployed from OperatorHub in the openshift-adp namespace."},
{term:"NAD",abbr:"NetworkAttachmentDefinition",cat:"acronym",def:"See: NetworkAttachmentDefinition. A CRD used with Multus CNI to attach secondary network interfaces to pods. Required for SR-IOV, macvlan, and other additional networks. Referenced via the k8s.v1.cni.cncf.io/networks pod annotation."},
{term:"VMI",abbr:"VirtualMachineInstance",cat:"acronym",def:"See: VirtualMachineInstance. The running instance of a KubeVirt VirtualMachine — analogous to a Pod for containers. Created when a VM is started. Each VMI corresponds to a virt-launcher pod on a node running the QEMU/KVM hypervisor process."},
{term:"CDI",abbr:"Containerized Data Importer",cat:"acronym",def:"See: ContainerizedDataImporter. The KubeVirt component that imports VM disk images into PVCs via DataVolume CRDs. Enables importing from HTTP, S3, container registries, and cloning from existing PVCs for OpenShift Virtualization VM provisioning."},
{term:"HCO",abbr:"HyperConverged Operator",cat:"acronym",def:"See: HyperConverged. The top-level OpenShift Virtualization CRD that orchestrates all virtualization components (KubeVirt, CDI, NetworkAddonsOperator). Creating an HCO CR in the openshift-cnv namespace deploys the full virtualization stack."},
{term:"ACM",abbr:"Advanced Cluster Management",cat:"acronym",def:"See: Advanced Cluster Management. Red Hat's multi-cluster management platform. Provides cluster lifecycle management, policy governance, GitOps application delivery, and observability across a fleet of OpenShift and Kubernetes clusters from a central hub."},
{term:"MCH",abbr:"MultiClusterHub",cat:"acronym",def:"See: MultiClusterHub. The top-level ACM CRD deployed on the hub cluster. Deploys all ACM components: cluster registry, policy engine, search indexer, application lifecycle manager, and observability stack."},
{term:"BSL",abbr:"BackupStorageLocation",cat:"acronym",def:"See: BackupStorageLocation. A Velero/OADP CRD defining the S3-compatible object store bucket where Kubernetes object backups are written. Must be healthy before Velero can create Backup CRs."},
{term:"VSL",abbr:"VolumeSnapshotLocation",cat:"acronym",def:"See: VolumeSnapshotLocation. A Velero/OADP CRD defining the CSI snapshot provider for PV backups. Used when snapshotting volumes during a Velero Backup operation."},
{term:"RBD",abbr:"RADOS Block Device",cat:"acronym",def:"See: Ceph RBD. Ceph's block storage layer. In ODF, the ocs-storagecluster-ceph-rbd StorageClass provisions RBD-backed RWO PersistentVolumes for databases and stateful apps requiring dedicated block storage."},
{term:"RGW",abbr:"RADOS Gateway",cat:"acronym",def:"The Ceph object storage gateway providing S3 and Swift-compatible APIs over a Ceph cluster. In ODF, the RGW backs the NooBaa S3 endpoint when configured as a BackingStore. Also used for OBC provisioning without NooBaa in some ODF configurations."},
{term:"DPA",abbr:"DataProtectionApplication",cat:"acronym",def:"See: DataProtectionApplication. The OADP CRD that configures the entire backup stack (Velero + plugins + BSL + VSL). Created after installing the OADP operator to deploy Velero with the desired storage provider configuration."},
{term:"VM",abbr:"VirtualMachine",cat:"acronym",def:"See: VirtualMachine. A KubeVirt CRD representing a VM definition (CPU, memory, disks, NICs). Manages the lifecycle of a running VirtualMachineInstance. Use: oc get vm"},
{term:"VMIM",abbr:"VirtualMachineInstanceMigration",cat:"acronym",def:"See: VirtualMachineInstanceMigration. A KubeVirt CRD that triggers live migration of a VMI to another node. Use: oc get vmim"},
{term:"VMIRS",abbr:"VirtualMachineInstanceReplicaSet",cat:"acronym",def:"See: VirtualMachineInstanceReplicaSet. Maintains a desired number of identical running VMIs. Use: oc get vmirs"},
{term:"VMPool",abbr:"VirtualMachinePool",cat:"acronym",def:"See: VirtualMachinePool. Manages a pool of identical VirtualMachine objects for scale-out VM workloads. Use: oc get vmpool"},
{term:"VMSnapshot",abbr:"VirtualMachineSnapshot",cat:"acronym",def:"See: VirtualMachineSnapshot. A point-in-time snapshot of a VirtualMachine's disks and config. Use: oc get vmsnapshot"},
{term:"VMRestore",abbr:"VirtualMachineRestore",cat:"acronym",def:"See: VirtualMachineRestore. Restores a VirtualMachine from a VirtualMachineSnapshot. Use: oc get vmrestore"},
{term:"DV",abbr:"DataVolume",cat:"acronym",def:"See: DataVolume. A CDI CRD that orchestrates importing or cloning disk images into PVCs for VM use. Use: oc get dv"},
{term:"SSP",abbr:"Scheduling Scale and Performance Operator",cat:"acronym",def:"See: SSP Operator. Manages VM templates, common-instancetypes, and the Template Validator webhook as part of the OpenShift Virtualization HyperConverged stack."},
{term:"HPP",abbr:"HostPathProvisioner",cat:"acronym",def:"See: HostPathProvisioner. Dynamically provisions local-storage PVs from node filesystem paths for use with OpenShift Virtualization, especially on single-node deployments."},
];
